INSERT INTO `products` (`id`, `item_type`, `category_id`, `sub_category_id`, `price`, `image_url`, `storage_asset_id`, `images`, `storage_image_ids`, `is_active`, `is_featured`, `order_num`, `product_code`, `stock_quantity`, `rating`, `review_count`, `created_at`, `updated_at`) VALUES ('bbbb0001-2222-4222-8222-bbbbbbbb0001','product','aaaa0003-1111-4111-8111-aaaaaaaa0003','bbbb0201-1111-4111-8111-bbbbbbbb0201',0.00,'/uploads/material/sogutma-kulesi-suyu-sartlandirma-filtrasyon-otomasyon-250x250-1.jpg',NULL,'[\"/uploads/material/sogutma-kulesi-suyu-sartlandirma-filtrasyon-otomasyon-250x250-1.jpg\", \"/uploads/slayt/9.png\", \"/uploads/slayt/2.png\", \"/uploads/material/closed-type-cooling-tower-250x250-1.jpeg\", \"/uploads/slayt/4.png\", \"/uploads/news/1717089282656.jpeg\", \"/uploads/material/closed-circuit-water-cooling-towers_1-250x250-1.jpg\", \"/uploads/slayt/6.png\", \"/uploads/material/closed-circuit-water-cooling-towers-250x250-1.jpg\"]','[]',1,1,100,'CC-CTP',0,5.00,0,'2026-02-27 13:25:27.155','2026-03-24 11:05:02.378'),('bbbb0002-2222-4222-8222-bbbbbbbb0002','product','aaaa0002-1111-4111-8111-aaaaaaaa0002','bbbb0102-1111-4111-8111-bbbbbbbb0102',0.00,'/uploads/product/su-sogutma-kulesi-2-li.jpg.jpg',NULL,'[\"/uploads/material/kapali-sistem-esanjor-250x250-1.jpg\", \"/uploads/material/closed-circuit-cooling-tower-kapali-tip-sogutma-kulesi-250x250-1.jpg\"]','[]',1,1,110,'CTP-SINGLE',0,5.00,0,'2026-02-27 13:25:27.176','2026-04-14 14:44:14.428'),('bbbb0003-2222-4222-8222-bbbbbbbb0003','product','aaaa0002-1111-4111-8111-aaaaaaaa0002','bbbb0102-1111-4111-8111-bbbbbbbb0102',0.00,'https://res.cloudinary.com/dbozv7wqd/image/upload/v1774263675/uploads/products/su-sogutma-kulesi-2-li.jpg.jpg',NULL,'[\"https://res.cloudinary.com/dbozv7wqd/image/upload/v1774263675/uploads/products/su-sogutma-kulesi-2-li.jpg.jpg\"]','[]',1,1,120,'DCTP-DOUBLE',0,5.00,0,'2026-02-27 13:25:27.194','2026-03-23 11:22:09.515'),('bbbb0004-2222-4222-8222-bbbbbbbb0004','product','aaaa0002-1111-4111